import{_ as a,c as t,o as s,ak as o,al as i}from"./chunks/framework.CUmoI4gT.js";const p=JSON.parse('{"title":"AireAssert Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireassert-v1-3-0.md","filePath":"aireblock-releases/aireassert-v1-3-0.md","lastUpdated":1778063574000}'),r={name:"aireblock-releases/aireassert-v1-3-0.md"};function n(l,e,c,d,h,m){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="aireassert-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+i+'"> AireAssert Release Notes</span> <a class="header-anchor" href="#aireassert-release-notes" aria-label="Permalink to “AireAssert Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.3.0<br><strong>Release Date:</strong> 7th May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Form Launching from Widget Actions — AA-962</li><li>Execute Task Actions from the Subject Screen — AA-948</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Reliable Searchable Dropdown Interactions — AA-935</li><li>Improved Enabled and Disabled State Handling — AA-936</li><li>Multi-Select Control Reliability — AA-938</li><li>Smarter Non-Production Form Detection — AA-957</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="form-launching-from-widget-actions-aa-962" tabindex="-1">Form Launching from Widget Actions (AA-962) <a class="header-anchor" href="#form-launching-from-widget-actions-aa-962" aria-label="Permalink to “Form Launching from Widget Actions (AA-962)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireAssert can now handle widget actions in AireFrame that redirect to a clinician form, automatically launching and interacting with the form as part of the test flow. This reuses the existing form-launching logic from the sidebar, ensuring consistency across test scenarios.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When your tests trigger widget actions that open a clinician form, AireAssert will now seamlessly continue into the form without any extra configuration. You can immediately start asserting form behaviour as part of the same test, saving time and reducing the need for workarounds.</p></div><h4 id="execute-task-actions-from-the-subject-screen-aa-948" tabindex="-1">Execute Task Actions from the Subject Screen (AA-948) <a class="header-anchor" href="#execute-task-actions-from-the-subject-screen-aa-948" aria-label="Permalink to “Execute Task Actions from the Subject Screen (AA-948)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireAssert now supports running actions from the task list on the subject screen, enabling end-to-end test coverage of task execution workflows directly from the subject page.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now write tests that execute tasks straight from the subject screen, giving you fuller coverage of your clinical workflows without needing to navigate away or split your test scenarios.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="reliable-searchable-dropdown-interactions-aa-935" tabindex="-1">Reliable Searchable Dropdown Interactions (AA-935) <a class="header-anchor" href="#reliable-searchable-dropdown-interactions-aa-935" aria-label="Permalink to “Reliable Searchable Dropdown Interactions (AA-935)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireAssert now waits for search results to fully load before continuing when interacting with searchable dropdown fields. Previously, tests could advance before a search had completed, leaving controls in an invalid state and causing failures later in the scenario.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your tests involving searchable dropdowns will be more stable and reliable. You no longer need to add manual wait steps or work around timing issues when selecting values from these controls.</p></div><h4 id="improved-enabled-and-disabled-state-handling-aa-936" tabindex="-1">Improved Enabled and Disabled State Handling (AA-936) <a class="header-anchor" href="#improved-enabled-and-disabled-state-handling-aa-936" aria-label="Permalink to “Improved Enabled and Disabled State Handling (AA-936)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Handling of enabled and disabled control states has been improved to more accurately reflect real-world form scenarios, addressing cases where state transitions were not being detected correctly.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Tests that verify whether form controls are enabled or disabled will now behave more predictably, giving you greater confidence in assertions around control availability throughout your test scenarios.</p></div><h4 id="multi-select-control-reliability-aa-938" tabindex="-1">Multi-Select Control Reliability (AA-938) <a class="header-anchor" href="#multi-select-control-reliability-aa-938" aria-label="Permalink to “Multi-Select Control Reliability (AA-938)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Multi-select controls now correctly wait for search results to complete before the test progresses. Date shorthand commands such as &quot;Today&quot;, &quot;Tomorrow&quot;, and &quot;One month ago&quot; have also been fixed for use within multi-select scenarios.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Tests using multi-select controls or relative date inputs will no longer fail due to timing issues. Your scenarios will proceed in the correct order, and date shorthands will work as expected throughout.</p></div><h4 id="smarter-non-production-form-detection-aa-957" tabindex="-1">Smarter Non-Production Form Detection (AA-957) <a class="header-anchor" href="#smarter-non-production-form-detection-aa-957" aria-label="Permalink to “Smarter Non-Production Form Detection (AA-957)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Detection of non-production forms — those displaying a development warning on their first screen — has been moved from compile time to runtime. AireAssert now inspects the <code>IsDevelopment</code> flag dynamically, enabling it to handle forms loaded from external sources such as AireGlu endpoints where the form state is not known in advance.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Tests involving forms loaded from dynamic sources will no longer require manual intervention to dismiss development warnings. AireAssert handles this automatically at runtime, keeping your test runs clean and uninterrupted.</p></div>',31)])])}const b=a(r,[["render",n]]);export{p as __pageData,b as default};
